async (params, browser) => {
  // Open seller page
  await browser.open(`${params.seller_url}`)

  // Wait for seller page to load
  await browser.waitForSelector('#page-section-detail-seller-info, #seller-profile-container, .a-box-inner', 15000)

  // Let page fully render
  await browser.wait(2000)

  // Scroll to load more info
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract seller information
  const seller_data = await browser.evaluate(`const nameEl = document.querySelector('#seller-name, #page-section-detail-seller-info h1, .a-box-inner h1, #sellerName'); const ratingEl = document.querySelector('#seller-feedback-summary .a-icon-star .a-icon-alt, #effective-timeperiod-rating-year .a-icon-alt, i.a-icon-star .a-icon-alt'); const reviewSections = document.querySelectorAll('#feedback-summary-table tr, .feedback-detail-list tr'); const feedbackStats = []; reviewSections.forEach(function(row) { const label = row.querySelector('td:first-child, .a-text-left'); const values = row.querySelectorAll('td:not(:first-child), .a-text-center'); if (label && values.length > 0) { const stats = []; values.forEach(function(v) { stats.push(v.textContent.trim()); }); feedbackStats.push({ period: label.textContent.trim(), values: stats }); } }); const ratingCountEl = document.querySelector('#seller-feedback-count, .feedback-detail-description, #effective-timeperiod-rating-count-year'); const locationEl = document.querySelector('#page-section-detail-seller-info .a-row:nth-child(2) span, #seller-info-address, .seller-address'); const aboutEl = document.querySelector('#page-section-detail-seller-info .a-section:last-of-type, #seller-blurb, .seller-description'); const detailRows = document.querySelectorAll('#page-section-detail-seller-info ul li, .a-unordered-list .a-list-item'); const details = []; detailRows.forEach(function(row) { const text = row.textContent.trim(); if (text && text.length > 3) { details.push(text); } }); const positiveRatingEl = document.querySelector('#seller-feedback-summary .a-size-extra-large, .a-size-extra-large'); const businessNameEl = document.querySelector('#page-section-detail-seller-info .a-row span.a-size-medium, .seller-business-name'); return { name: nameEl ? nameEl.textContent.trim() : '', business_name: businessNameEl ? businessNameEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', positive_rating_percentage: positiveRatingEl ? positiveRatingEl.textContent.trim() : '', review_count: ratingCountEl ? ratingCountEl.textContent.trim() : '', location: locationEl ? locationEl.textContent.trim() : '', about: aboutEl ? aboutEl.textContent.trim().substring(0, 1000) : '', feedback_stats: feedbackStats, details: details.slice(0, 10), url: window.location.href }`)

  return seller_data
}
